slides.code:
.card {
  background: white;

  /* Nest selectors */
  .title { font-weight: bold; }
  .body  { color: #333; }

  /* Pseudo-classes */
  &:hover { box-shadow: 0 4px 12px #0002; }
  &:focus-within { outline: 2px solid blue; }

  /* Media queries inline */
  @media (width &lt; 768px) {
    padding: 1rem;
  }
}
